import{_ as e,o as i,c as a,aj as r}from"./chunks/framework.Co0EVkx3.js";const b=JSON.parse('{"title":"AnvilLib 文档","description":"","frontmatter":{},"headers":[],"relativePath":"posts/docs/anvillib/index.md","filePath":"posts/docs/anvillib/index.md","lastUpdated":1773837867000}'),o={name:"posts/docs/anvillib/index.md"};function l(n,t,d,s,c,h){return i(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="anvillib-文档" tabindex="-1">AnvilLib 文档 <a class="header-anchor" href="#anvillib-文档" aria-label="Permalink to “AnvilLib 文档”">​</a></h1><p><strong>AnvilLib</strong> 是由 <a href="https://github.com/Anvil-Dev" target="_blank" rel="noreferrer">Anvil Dev</a> 开发的 NeoForge 模组库，为 Minecraft（1.21.1）模组开发者提供一系列实用的工具和框架。</p><h2 id="模块概览" tabindex="-1">模块概览 <a class="header-anchor" href="#模块概览" aria-label="Permalink to “模块概览”">​</a></h2><p>AnvilLib 采用模块化设计，每个模块可以独立引入，也可以引入聚合包获得所有功能。</p><table tabindex="0"><thead><tr><th>模块</th><th>Maven Artifact（含前缀 <code>dev.anvilcraft.lib:</code>）</th><th>说明</th></tr></thead><tbody><tr><td><strong>Config</strong></td><td><code>anvillib-config-neoforge-1.21.1</code></td><td>基于注解的配置系统</td></tr><tr><td><strong>Integration</strong></td><td><code>anvillib-integration-neoforge-1.21.1</code></td><td>模组兼容性集成框架</td></tr><tr><td><strong>Network</strong></td><td><code>anvillib-network-neoforge-1.21.1</code></td><td>网络通信与数据包自动注册</td></tr><tr><td><strong>Recipe</strong></td><td><code>anvillib-recipe-neoforge-1.21.1</code></td><td>世界内配方系统</td></tr><tr><td><strong>Moveable Entity Block</strong></td><td><code>anvillib-moveable-entity-block-neoforge-1.21.1</code></td><td>可被活塞推动的方块实体支持</td></tr><tr><td><strong>Registrum</strong></td><td><code>anvillib-registrum-neoforge-1.21.1</code></td><td>简化的注册系统（基于 Registrate）</td></tr><tr><td><strong>Main（聚合）</strong></td><td><code>anvillib-neoforge-1.21.1</code></td><td>包含所有子模块的聚合发行包</td></tr></tbody></table><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to “环境要求”">​</a></h2><ul><li>Java 21+</li><li>Minecraft 1.21.1</li><li>NeoForge 21.1.x</li></ul><h2 id="文档导航" tabindex="-1">文档导航 <a class="header-anchor" href="#文档导航" aria-label="Permalink to “文档导航”">​</a></h2><ol><li><a href="./01_getting_started.html">快速开始（依赖引入）</a></li><li><a href="./02_config.html">Config 配置模块</a></li><li><a href="./03_integration.html">Integration 集成模块</a></li><li><a href="./04_network.html">Network 网络模块</a></li><li><a href="./05_recipe.html">Recipe 世界内配方模块</a></li><li><a href="./06_moveable_entity_block.html">Moveable Entity Block 模块</a></li><li><a href="./07_registrum.html">Registrum 注册模块</a></li></ol>',9)])])}const f=e(o,[["render",l]]);export{b as __pageData,f as default};
